        -1000.0,
        1000.0
      ],
      "description": "Penalize large angle and angular velocity."
    },
    {
      "id": "fuel_efficiency",
      "expression": "-0.1 * 1.0",
      "clip": [
        -1000.0,
        1000.0
      ],
      "description": "Per-step survival penalty to create urgency for task completion."
    },
